package main

import (
    "testing"
)

func Add(a, b int) int {
    return a + b
}

func Subtract(a, b int) int {
    return a - b
}

func Multiply(a, b int) int {
    return a * b
}

func Divide(a, b int) (int, error) {
    if b == 0 {
        return 0, ErrDivideByZero
    }
    return a / b, nil
}

var ErrDivideByZero = errors.New("cannot divide by zero")

func TestAdd(t *testing.T) {
    result := Add(2, 3)
    expected := 5
    if result != expected {
        t.Errorf("Add(2, 3) = %d; want %d", result, expected)
    }

    result = Add(-1, 5)
    expected = 4
    if result != expected {
        t.Errorf("Add(-1, 5) = %d; want %d", result, expected)
    }
}

func TestSubtract(t *testing.T) {
    result := Subtract(10, 3)
    expected := 7
    if result != expected {
        t.Errorf("Subtract(10, 3) = %d; want %d", result, expected)
    }

    result = Subtract(3, 10)
    expected = -7
    if result != expected {
        t.Errorf("Subtract(3, 10) = %d; want %d", result, expected)
    }
}

func TestMultiply(t *testing.T) {
    result := Multiply(4, 5)
    expected := 20
    if result != expected {
        t.Errorf("Multiply(4, 5) = %d; want %d", result, expected)
    }

    result = Multiply(4, 0)
    expected = 0
    if result != expected {
        t.Errorf("Multiply(4, 0) = %d; want %d", result, expected)
    }
}

func TestDivide(t *testing.T) {
    result, err := Divide(10, 2)
    if err != nil {
        t.Errorf("Divide(10, 2) returned error: %v", err)
    }
    expected := 5
    if result != expected {
        t.Errorf("Divide(10, 2) = %d; want %d", result, expected)
    }
}

func TestDivideByZero(t *testing.T) {
    _, err := Divide(10, 0)
    if err == nil {
        t.Error("Divide(10, 0) should return an error")
    }
}
